   870→	dispose(): void {
   871→		markAsDisposed(this);
   872→		this._isDisposed = true;
   873→		this.clearAndDisposeAll();
   874→	}
   875→
   876→	/**
   877→	 * Disposes of all stored values and clear the set, but DO NOT mark this object as disposed.
