   148→	}
   149→
   150→	isEqual(uri1: URI | undefined, uri2: URI | undefined, ignoreFragment: boolean = false): boolean {
   151→		if (uri1 === uri2) {
   152→			return true;
   153→		}
   154→		if (!uri1 || !uri2) {
   155→			return false;
   156→		}
   157→		return this.getComparisonKey(uri1, ignoreFragment) === this.getComparisonKey(uri2, ignoreFragment);
