   173→			if (base.scheme === Schemas.file) {
   174→				return extpath.isEqualOrParent(originalFSPath(base), originalFSPath(parentCandidate), this._ignorePathCasing(base)) && base.query === parentCandidate.query && (ignoreFragment || base.fragment === parentCandidate.fragment);
   175→			}
   176→			if (isEqualAuthority(base.authority, parentCandidate.authority)) {
   177→				return extpath.isEqualOrParent(base.path, parentCandidate.path, this._ignorePathCasing(base), '/') && base.query === parentCandidate.query && (ignoreFragment || base.fragment === parentCandidate.fragment);
   178→			}
   179→		}
   180→		return false;
   181→	}
