   119→/**
   120→ * Wraps a cancellable promise such that it is no cancellable. Can be used to
   121→ * avoid issues with shared promises that would normally be returned as
   122→ * cancellable to consumers.
   123→ */
   124→export function notCancellablePromise<T>(promise: CancelablePromise<T>): Promise<T> {
