   150→export function raceTimeout<T>(promise: Promise<T>, timeout: number, onTimeout?: () => void): Promise<T | undefined> {
   151→	let promiseResolve: ((value: T | undefined) => void) | undefined = undefined;
   152→
   153→	const timer = setTimeout(() => {
   154→		promiseResolve?.(undefined);
   155→		onTimeout?.();
   156→	}, timeout);
   157→
   158→	return Promise.race([
   159→		promise.finally(() => clearTimeout(timer)),
   160→		new Promise<T | undefined>(resolve => promiseResolve = resolve)
   161→	]);
   162→}
