   180→export function promiseWithResolvers<T>(): { promise: Promise<T>; resolve: (value: T | PromiseLike<T>) => void; reject: (err?: any) => void } {
   181→	let resolve: (value: T | PromiseLike<T>) => void;
   182→	let reject: (reason?: any) => void;
