   588→/**
   589→ * Runs the provided list of promise factories in sequential order. The returned
   590→ * promise will complete to an array of results from each promise.
   591→ */
   592→
   593→export function sequence<T>(promiseFactories: ITask<Promise<T>>[]): Promise<T[]> {
   594→	const results: T[] = [];
   595→	let index = 0;
   596→	const len = promiseFactories.length;
   597→
   598→	function next(): Promise<T> | null {
   599→		return index < len ? promiseFactories[index++]() : null;
   600→	}
   601→
   602→	function thenHandler(result: unknown): Promise<any> {
   603→		if (result !== undefined && result !== null) {
   604→			results.push(result as T);
   605→		}
   606→
   607→		const n = next();
   608→		if (n) {
   609→			return n.then(thenHandler);
   610→		}
   611→
   612→		return Promise.resolve(results);
   613→	}
   614→
   615→	return Promise.resolve(null).then(thenHandler);
   616→}
