   618→export function first<T>(promiseFactories: ITask<Promise<T>>[], shouldStop: (t: T) => boolean = t => !!t, defaultValue: T | null = null): Promise<T | null> {
   619→	let index = 0;
   620→	const len = promiseFactories.length;
   621→
   622→	const loop: () => Promise<T | null> = () => {
   623→		if (index >= len) {
   624→			return Promise.resolve(defaultValue);
   625→		}
   626→
   627→		const factory = promiseFactories[index++];
   628→		const promise = Promise.resolve(factory());
   629→
   630→		return promise.then(result => {
   631→			if (shouldStop(result)) {
   632→				return Promise.resolve(result);
   633→			}
   634→
   635→			return loop();
   636→		});
   637→	};
   638→
   639→	return loop();
   640→}
