   642→/**
   643→ * Returns the result of the first promise that matches the "shouldStop",
   644→ * running all promises in parallel. Supports cancelable promises.
   645→ */
   646→export function firstParallel<T>(promiseList: Promise<T>[], shouldStop?: (t: T) => boolean, defaultValue?: T | null): Promise<T | null>;
   647→export function firstParallel<T, R extends T>(promiseList: Promise<T>[], shouldStop: (t: T) => t is R, defaultValue?: R | null): Promise<R | null>;
   648→export function firstParallel<T>(promiseList: Promise<T>[], shouldStop: (t: T) => boolean = t => !!t, defaultValue: T | null = null) {
   649→	if (promiseList.length === 0) {
   650→		return Promise.resolve(defaultValue);
   651→	}
   652→
   653→	let todo = promiseList.length;
   654→	const finish = () => {
   655→		todo = -1;
   656→		for (const promise of promiseList) {
   657→			(promise as Partial<CancelablePromise<T>>).cancel?.();
   658→		}
   659→	};
   660→
   661→	return new Promise<T | null>((resolve, reject) => {
   662→		for (const promise of promiseList) {
   663→			promise.then(result => {
   664→				if (--todo >= 0 && shouldStop(result)) {
   665→					finish();
   666→					resolve(result);
   667→				} else if (todo === 0) {
   668→					resolve(defaultValue);
   669→				}
   670→			})
   671→				.catch(err => {
   672→					if (--todo >= 0) {
   673→						finish();
   674→						reject(err);
   675→					}
   676→				});
   677→		}
   678→	});
   679→}
