```typescript
export function createCancelablePromise<T>(
	callback: (token: CancellationToken) => Promise<T>
): CancelablePromise<T> {
	const source = new CancellationTokenSource();
	const thenable = callback(source.token);

	let isCancelled = false;
	const promise = new Promise<T>((resolve, reject) => {
		const subscription = source.token.onCancellationRequested(() => {
			isCancelled = true;
			subscription.dispose();  // ← dispose the listener
			reject(new CancellationError());
		});
		Promise.resolve(thenable).then(value => {
			subscription.dispose();  // ← cleanup on settle
			source.dispose();

			if (!isCancelled && isDisposable(value)) {
				value.dispose();  // ← auto-dispose resolving disposable
			}
		}, ...);
	});

	return <CancelablePromise<T>>new class {
		cancel() {
			source.cancel();
			source.dispose();
		}
		then<TResult1 = T>(resolve?, reject?): Promise<TResult1 | TResult2> {
			return promise.then(resolve, reject);
		}
		...
	};
}
```

